#include<bits/stdc++.h>
using namespace std;
bool a[2][1000005];
int n,x,y,len=0;
struct node{
	int x,y,j;
}w[100000];
bool cmp(node a,node b){
	if(a.j==b.j){
		if(a.y==y)return true;
		else return false;
	}	
	else return a.j<b.j;
}
int main(void){
	cin>>n;
	for(int i=0;i<2;i++){
		for(int j=1;j<=n;j++){
			cin>>a[i][j];
			if(a[i][j]==0){
				node t;
				t.x=j;
				t.y=i;
				w[len]=t;
				len++;
			}
			
		}
	}
	if(len==0){
		cout<<-1;
		return false;
	}
	cin>>y>>x;
	for(int i=0;i<len;i++){
		w[i].j=abs(w[i].x-x);
	}
	sort(w,w+len,cmp);
	cout<<abs(w[0].y-y)<<' '<<abs(w[0].x-x); 
	return false;
}
